INSERT INTO public.exercise_details (id, name, primary_muscle, steps, form_cues)
VALUES
  ('ex-squat', 'Squat', 'Quads', '{"Stand with feet shoulder-width apart.","Lower your hips back and down, as if sitting in a chair.","Keep your chest up and your back straight.","Push through your heels to return to the starting position."}', '{"Keep your knees tracking over your toes, don''t let them cave inwards."}'),
  ('ex-push-up', 'Push-up', 'Chest', '{"Start in a high plank position with hands slightly wider than shoulder-width.","Lower your body until your chest is just above the floor.","Push back up to the starting position.","Keep your core tight and body in a straight line."}', '{"Don''t let your hips sag or hike up into a mountain shape."}'),
  ('ex-plank', 'Plank', 'Core', '{"Rest on your forearms and toes.","Keep your body in a straight line from your head to your heels.","Engage your core and hold the position."}', '{"Squeeze your glutes to help maintain a straight lower back."}'),
  ('ex-lunge', 'Lunge', 'Quads', '{"Step forward with one leg.","Lower your hips until both knees are bent at a 90-degree angle.","Push off your front foot to return to the starting position.","Repeat on the other side."}', '{"Ensure your front knee is directly above your ankle, not pushed out too far."}'),
  ('ex-burpees', 'Burpees', 'Full Body', '{"Stand straight, then squat down and place your hands on the floor.","Jump your feet back to a plank position.","Do one push-up (optional).","Jump your feet back in towards your hands.","Explosively jump up into the air with arms overhead."}', '{"Modify by stepping back instead of jumping if needed."}'),
  ('ex-goblet-squats', 'Goblet Squats', 'Quads', '{"Hold a weight vertically against your chest.","Perform a standard squat by lowering your hips back and down.","Keep the weight close to your body and your chest high.","Push back up to standing."}', '{"Imagine sitting directly straight down between your heels."}'),
  ('ex-glute-bridges', 'Glute Bridges', 'Glutes', '{"Lie on your back with knees bent and feet flat on the floor.","Squeeze your glutes and push your hips towards the ceiling.","Hold for a second at the top.","Slowly lower back down."}', '{"Drive through your heels, not your toes."}'),
  ('ex-dumbbell-rows', 'Dumbbell Rows', 'Back', '{"Hinge forward at the hips, keeping your back straight.","Hold weights hanging straight down.","Pull the weights up toward your hips, squeezing your shoulder blades together.","Slowly lower the weights."}', '{"Keep your elbows close to your body as you pull."}'),
  ('ex-jumping-jacks', 'Jumping Jacks', 'Cardio', '{"Stand upright with legs together and arms at your sides.","Jump up, spreading your legs and bringing your arms above your head.","Jump again, returning to the starting position."}', '{"Land softly on the balls of your feet."}'),
  ('ex-farmers-walk', 'Farmers Walk', 'Core', '{"Pick up a heavy weight in each hand.","Stand tall with your shoulders pulled back and down.","Walk forward with short, quick steps while maintaining a tight core."}', '{"Do not let the weights pull your shoulders forward."}'),
  ('ex-dumbbell-bench-press', 'Dumbbell Bench Press', 'Target Muscle Group', '{"1. Position yourself correctly for standard Dumbbell Bench Press.","2. Contract the target muscle to initiate the movement.","3. Complete the full range of motion under control.","4. Return slowly to the starting position."}', '{"Keep your wrists straight and drive forcefully."}'),
  ('ex-barbell-bench-press', 'Barbell Bench Press', 'Target Muscle Group', '{"1. Position yourself correctly for standard Barbell Bench Press.","2. Contract the target muscle to initiate the movement.","3. Complete the full range of motion under control.","4. Return slowly to the starting position."}', '{"Keep your wrists straight and drive forcefully."}'),
  ('ex-incline-dumbbell-press', 'Incline Dumbbell Press', 'Target Muscle Group', '{"1. Position yourself correctly for standard Incline Dumbbell Press.","2. Contract the target muscle to initiate the movement.","3. Complete the full range of motion under control.","4. Return slowly to the starting position."}', '{"Keep your wrists straight and drive forcefully."}'),
  ('ex-machine-chest-press', 'Machine Chest Press', 'Target Muscle Group', '{"1. Position yourself correctly for standard Machine Chest Press.","2. Contract the target muscle to initiate the movement.","3. Complete the full range of motion under control.","4. Return slowly to the starting position."}', '{"Keep your wrists straight and drive forcefully."}'),
  ('ex-dumbbell-flyes', 'Dumbbell Flyes', 'Target Muscle Group', '{"1. Position yourself correctly for standard Dumbbell Flyes.","2. Contract the target muscle to initiate the movement.","3. Complete the full range of motion under control.","4. Return slowly to the starting position."}', '{"Keep your core braced and breathe naturally throughout."}'),
  ('ex-cable-crossovers', 'Cable Crossovers', 'Target Muscle Group', '{"1. Position yourself correctly for standard Cable Crossovers.","2. Contract the target muscle to initiate the movement.","3. Complete the full range of motion under control.","4. Return slowly to the starting position."}', '{"Keep your core braced and breathe naturally throughout."}'),
  ('ex-resistance-band-chest-press', 'Resistance Band Chest Press', 'Target Muscle Group', '{"1. Position yourself correctly for standard Resistance Band Chest Press.","2. Contract the target muscle to initiate the movement.","3. Complete the full range of motion under control.","4. Return slowly to the starting position."}', '{"Keep your wrists straight and drive forcefully."}'),
  ('ex-arm-circles', 'Arm Circles', 'Target Muscle Group', '{"1. Position yourself correctly for standard Arm Circles.","2. Contract the target muscle to initiate the movement.","3. Complete the full range of motion under control.","4. Return slowly to the starting position."}', '{"Keep your core braced and breathe naturally throughout."}'),
  ('ex-pull-ups', 'Pull-ups', 'Target Muscle Group', '{"1. Position yourself correctly for standard Pull-ups.","2. Contract the target muscle to initiate the movement.","3. Complete the full range of motion under control.","4. Return slowly to the starting position."}', '{"Keep your core braced and breathe naturally throughout."}'),
